import{_ as a,c as e,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Quick Start: Install, Configure Gateway, Send First Message, and Understand DM Pairing Protection | Clawdbot Tutorial","description":"This chapter guides you through your first use of Clawdbot, including installation, configuration, starting Gateway, sending your first message, and understanding the DM pairing protection mechanism.","frontmatter":{"title":"Quick Start: Install, Configure Gateway, Send First Message, and Understand DM Pairing Protection | Clawdbot Tutorial","sidebarTitle":"Quick Start","subtitle":"Quick Start: From Installation to Your First Message","description":"This chapter guides you through your first use of Clawdbot, including installation, configuration, starting Gateway, sending your first message, and understanding the DM pairing protection mechanism.","tags":["Getting Started","Quick Start"],"prerequisite":[],"order":10},"headers":[],"relativePath":"moltbot/moltbot/start/index.md","filePath":"moltbot/moltbot/start/index.md"}'),r={name:"moltbot/moltbot/start/index.md"};function s(o,t,l,c,d,u){return i(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="quick-start-from-installation-to-your-first-message" tabindex="-1">Quick Start: From Installation to Your First Message <a class="header-anchor" href="#quick-start-from-installation-to-your-first-message" aria-label="Permalink to &quot;Quick Start: From Installation to Your First Message&quot;">​</a></h1><p>Welcome to Clawdbot! This chapter will guide you through the complete process of using Clawdbot from scratch. Whether you want to quickly experience an AI assistant or dive deep into configuration options, we have corresponding tutorials for you.</p><hr><h2 id="chapter-overview" tabindex="-1">Chapter Overview <a class="header-anchor" href="#chapter-overview" aria-label="Permalink to &quot;Chapter Overview&quot;">​</a></h2><p>This chapter contains 5 tutorials covering the complete onboarding flow for Clawdbot: from installing software, configuring AI models and communication channels, to starting the Gateway daemon, sending your first message, and finally understanding the default security protection mechanism. After completing this chapter, you will have a fully functional personal AI assistant.</p><hr><h2 id="recommended-learning-path" tabindex="-1">Recommended Learning Path <a class="header-anchor" href="#recommended-learning-path" aria-label="Permalink to &quot;Recommended Learning Path&quot;">​</a></h2><p>We recommend following these tutorials in order:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[getting-started&lt;br&gt;Quick Start] --&gt; B[onboarding-wizard&lt;br&gt;Onboarding Wizard]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[gateway-startup&lt;br&gt;Start Gateway]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[first-message&lt;br&gt;Send First Message]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[pairing-approval&lt;br&gt;DM Pairing &amp; Access Control]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#3b82f6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#10b981,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#f59e0b,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#8b5cf6,color:#fff</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#ef4444,color:#fff</span></span></code></pre></div><p><strong>Learning Sequence</strong>:</p><ol><li><strong>Quick Start</strong> (required): Complete basic installation and configuration, prerequisite for all subsequent learning</li><li><strong>Onboarding Wizard</strong> (recommended): Deep dive into wizard options, for users who want fine-grained configuration</li><li><strong>Start Gateway</strong> (required): Learn how to start and manage the Gateway daemon</li><li><strong>Send First Message</strong> (required): Verify configuration is correct and start using the AI assistant</li><li><strong>DM Pairing &amp; Access Control</strong> (recommended): Understand the default security mechanism to protect your AI assistant</li></ol><div class="tip custom-block"><p class="custom-block-title">Fast Track</p><p>If you just want to quickly experience it, you can learn only the &quot;Quick Start&quot; and &quot;Start Gateway&quot; tutorials, then send messages directly. Other tutorials can be learned on-demand later.</p></div><hr><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before starting this chapter, please ensure:</p><ul><li><strong>Node.js</strong>: ≥ 22.12.0 (check with <code>node -v</code>)</li><li><strong>Operating System</strong>: macOS / Linux / Windows (WSL2)</li><li><strong>Package Manager</strong>: npm / pnpm / bun</li><li><strong>AI Model Account</strong> (recommended): <ul><li>Anthropic Claude account (Pro/Max subscription), supports OAuth flow</li><li>Or prepare API Key from OpenAI / DeepSeek / OpenRouter and other providers</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">Windows Users Notice</p><p><strong>WSL2</strong> is strongly recommended on Windows because:</p><ul><li>Many channels depend on local binaries</li><li>Daemons (launchd/systemd) are not available on Windows</li></ul></div><hr><h2 id="sub-page-navigation" tabindex="-1">Sub-page Navigation <a class="header-anchor" href="#sub-page-navigation" aria-label="Permalink to &quot;Sub-page Navigation&quot;">​</a></h2><h3 id="_1-quick-start-⭐-core-tutorial" tabindex="-1"><a href="./getting-started/">1. Quick Start</a> ⭐ Core Tutorial <a class="header-anchor" href="#_1-quick-start-⭐-core-tutorial" aria-label="Permalink to &quot;[1. Quick Start](./getting-started/) ⭐ Core Tutorial&quot;">​</a></h3><p><strong>What You&#39;ll Learn</strong>:</p><ul><li>✅ Install Clawdbot on your device</li><li>✅ Configure AI model authentication (Anthropic / OpenAI / other providers)</li><li>✅ Start the Gateway daemon</li><li>✅ Send your first message via WebChat or configured channels</li></ul><p><strong>Target Audience</strong>: All users, must-read tutorial</p><p><strong>Estimated Time</strong>: 15-20 minutes</p><p><strong>Main Content</strong>:</p><ul><li>Install Clawdbot using npm/pnpm/bun</li><li>Run onboarding wizard to complete basic configuration</li><li>Start Gateway and verify status</li><li>Send test messages via CLI or channels</li></ul><p><strong>Prerequisites</strong>: None</p><hr><h3 id="_2-onboarding-wizard" tabindex="-1"><a href="./onboarding-wizard/">2. Onboarding Wizard</a> <a class="header-anchor" href="#_2-onboarding-wizard" aria-label="Permalink to &quot;[2. Onboarding Wizard](./onboarding-wizard/)&quot;">​</a></h3><p><strong>What You&#39;ll Learn</strong>:</p><ul><li>✅ Complete full configuration using the interactive wizard</li><li>✅ Understand the difference between QuickStart and Manual modes</li><li>✅ Configure Gateway networking, authentication, and Tailscale</li><li>✅ Set up AI model providers (setup-token and API Key)</li><li>✅ Enable communication channels (WhatsApp, Telegram, etc.)</li><li>✅ Install and manage skill packages</li></ul><p><strong>Target Audience</strong>: Users who want fine-grained configuration, understand advanced options</p><p><strong>Estimated Time</strong>: 20-30 minutes</p><p><strong>Main Content</strong>:</p><ul><li>QuickStart vs Manual mode selection</li><li>Gateway network configuration (ports, binding, authentication)</li><li>AI model authentication methods (setup-token recommended)</li><li>Communication channel configuration flow</li><li>Skill system introduction</li></ul><p><strong>Prerequisites</strong>: <a href="./getting-started/">Quick Start</a></p><hr><h3 id="_3-start-gateway-⭐-core-tutorial" tabindex="-1"><a href="./gateway-startup/">3. Start Gateway</a> ⭐ Core Tutorial <a class="header-anchor" href="#_3-start-gateway-⭐-core-tutorial" aria-label="Permalink to &quot;[3. Start Gateway](./gateway-startup/) ⭐ Core Tutorial&quot;">​</a></h3><p><strong>What You&#39;ll Learn</strong>:</p><ul><li>✅ Start Gateway foreground process using command line</li><li>✅ Configure Gateway as background daemon (macOS LaunchAgent / Linux systemd / Windows Scheduled Task)</li><li>✅ Understand different binding modes (loopback / LAN / Tailnet) and authentication methods</li><li>✅ Switch between development mode and production mode</li><li>✅ Use <code>--force</code> to forcefully release occupied ports</li></ul><p><strong>Target Audience</strong>: All users, must-read tutorial</p><p><strong>Estimated Time</strong>: 15-20 minutes</p><p><strong>Main Content</strong>:</p><ul><li>Foreground mode vs daemon mode</li><li>Binding mode selection (loopback / LAN / Tailnet / Auto)</li><li>Authentication method configuration (Token / Password / Tailscale Identity)</li><li>Development mode (<code>--dev</code>) vs production mode</li><li>Service management commands (install / start / stop / restart)</li><li>Port conflict handling (<code>--force</code>)</li></ul><p><strong>Prerequisites</strong>: <a href="./onboarding-wizard/">Onboarding Wizard</a></p><hr><h3 id="_4-send-first-message-⭐-core-tutorial" tabindex="-1"><a href="./first-message/">4. Send First Message</a> ⭐ Core Tutorial <a class="header-anchor" href="#_4-send-first-message-⭐-core-tutorial" aria-label="Permalink to &quot;[4. Send First Message](./first-message/) ⭐ Core Tutorial&quot;">​</a></h3><p><strong>What You&#39;ll Learn</strong>:</p><ul><li>✅ Send messages via WebChat interface</li><li>✅ Chat with AI assistant via configured channels (WhatsApp / Telegram / Slack, etc.)</li><li>✅ Understand message routing and response flow</li><li>✅ Use AI assistant to execute basic tasks (query, summarize, code generation, etc.)</li></ul><p><strong>Target Audience</strong>: All users, must-read tutorial</p><p><strong>Estimated Time</strong>: 10-15 minutes</p><p><strong>Main Content</strong>:</p><ul><li>WebChat interface usage</li><li>Message sending methods for each channel</li><li>Message format and reply mechanism</li><li>Common task examples (query information, generate code, summarize text)</li><li>Debugging and troubleshooting</li></ul><p><strong>Prerequisites</strong>: <a href="./gateway-startup/">Start Gateway</a></p><hr><h3 id="_5-dm-pairing-access-control" tabindex="-1"><a href="./pairing-approval/">5. DM Pairing &amp; Access Control</a> <a class="header-anchor" href="#_5-dm-pairing-access-control" aria-label="Permalink to &quot;[5. DM Pairing &amp; Access Control](./pairing-approval/)&quot;">​</a></h3><p><strong>What You&#39;ll Learn</strong>:</p><ul><li>✅ Understand the default DM pairing protection mechanism</li><li>✅ Approve or reject pairing requests from unknown senders</li><li>✅ Configure allowlist and blocklist</li><li>✅ Set up access control policies</li><li>✅ Understand pairing modes and security best practices</li></ul><p><strong>Target Audience</strong>: Users concerned about security, recommended learning</p><p><strong>Estimated Time</strong>: 10-15 minutes</p><p><strong>Main Content</strong>:</p><ul><li>DM pairing mechanism principles</li><li>Pairing flow and user experience</li><li>Allowlist and blocklist configuration</li><li>Access control policy settings</li><li>Security best practices</li></ul><p><strong>Prerequisites</strong>: <a href="./first-message/">Send First Message</a></p><hr><h2 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h2><h3 id="q-should-i-learn-all-tutorials" tabindex="-1">Q: Should I learn all tutorials? <a class="header-anchor" href="#q-should-i-learn-all-tutorials" aria-label="Permalink to &quot;Q: Should I learn all tutorials?&quot;">​</a></h3><p><strong>A</strong>: Not necessarily. If you want to get started quickly, you only need to learn the two core tutorials &quot;Quick Start&quot; and &quot;Start Gateway&quot;, then you can start using Clawdbot. Other tutorials can be learned on-demand as needed.</p><h3 id="q-will-skipping-certain-tutorials-have-any-impact" tabindex="-1">Q: Will skipping certain tutorials have any impact? <a class="header-anchor" href="#q-will-skipping-certain-tutorials-have-any-impact" aria-label="Permalink to &quot;Q: Will skipping certain tutorials have any impact?&quot;">​</a></h3><p><strong>A</strong>: No. Each tutorial is independent, but &quot;Quick Start&quot; is the foundation and includes installation and basic configuration, so it&#39;s recommended to learn it first. Other tutorials can be selectively learned based on your needs.</p><h3 id="q-i-m-already-familiar-with-ai-assistants-can-i-skip-the-basic-tutorials" tabindex="-1">Q: I&#39;m already familiar with AI assistants, can I skip the basic tutorials? <a class="header-anchor" href="#q-i-m-already-familiar-with-ai-assistants-can-i-skip-the-basic-tutorials" aria-label="Permalink to &quot;Q: I&#39;m already familiar with AI assistants, can I skip the basic tutorials?&quot;">​</a></h3><p><strong>A</strong>: Yes. If you&#39;re already familiar with similar AI assistant tools, you can skip &quot;Quick Start&quot; and directly learn &quot;Onboarding Wizard&quot; and &quot;Start Gateway&quot; to understand Clawdbot&#39;s specific configuration and startup methods.</p><h3 id="q-what-can-i-do-after-completing-this-chapter" tabindex="-1">Q: What can I do after completing this chapter? <a class="header-anchor" href="#q-what-can-i-do-after-completing-this-chapter" aria-label="Permalink to &quot;Q: What can I do after completing this chapter?&quot;">​</a></h3><p><strong>A</strong>: After completing this chapter, you will have a fully functional Clawdbot system that can:</p><ul><li>Chat with AI assistant via WebChat or multiple channels</li><li>Let AI execute basic tasks (query information, generate code, summarize text, etc.)</li><li>Use DM pairing mechanism to protect security</li><li>Continue learning advanced features (multi-channel configuration, tool system, skill platform, etc.)</li></ul><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you can continue learning:</p><ul><li><strong><a href="./../../platforms/channels-overview/">Multi-channel System Overview</a></strong>: Learn about all communication channels supported by Clawdbot and their characteristics</li><li><strong><a href="./../../platforms/whatsapp/">WhatsApp Channel</a></strong>: Deep dive into WhatsApp channel configuration and usage</li><li><strong><a href="./../../platforms/telegram/">Telegram Channel</a></strong>: Deep dive into Telegram channel configuration and usage</li><li><strong><a href="./../../platforms/webchat/">WebChat Interface</a></strong>: Learn about the built-in WebChat interface features</li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Choose the corresponding channel for in-depth learning based on your usage needs. If you primarily use a certain channel (such as WhatsApp or Telegram), you can prioritize learning that channel&#39;s dedicated tutorial.</p></div>`,79)])])}const h=a(r,[["render",s]]);export{g as __pageData,h as default};
